#include <bits/stdc++.h>
using namespace std;vector<int>p;
int f(int x){return p[x]==x?x:p[x]=f(p[x]);}
int main(){int n,m;scanf("%d %d",&n,&m);vector<array<long long,3>>ed(m);for(auto&x:ed)scanf("%lld %lld %lld",&x[1],&x[2],&x[0]);sort(ed.begin(),ed.end());p.resize(n+1);for(int i=1;i<=n;i++)p[i]=i;long long sum=0,mx=0;for(auto&x:ed){int a=f(x[1]),b=f(x[2]);if(a!=b){p[a]=b;sum+=x[0];mx=max(mx,x[0]);}}printf("%lld\n",sum-mx);}
